import{_ as t,o as r,c as s,a2 as i}from"./chunks/framework.2UjvPF9X.js";const m=JSON.parse(`{"title":"Collection d'Anti-patterns RxJS","description":"Comprendre les anti-patterns RxJS pour écrire du code plus robuste et maintenable. Explore systématiquement les problèmes fréquents et leurs solutions : mauvaise utilisation des Subjects, souscriptions imbriquées, branchements conditionnels dans subscribe, prolifération de drapeaux, et autres problèmes rencontrés sur le terrain.","frontmatter":{"description":"Comprendre les anti-patterns RxJS pour écrire du code plus robuste et maintenable. Explore systématiquement les problèmes fréquents et leurs solutions : mauvaise utilisation des Subjects, souscriptions imbriquées, branchements conditionnels dans subscribe, prolifération de drapeaux, et autres problèmes rencontrés sur le terrain."},"headers":[],"relativePath":"fr/guide/anti-patterns/index.md","filePath":"fr/guide/anti-patterns/index.md","lastUpdated":1765219888000}`),a={name:"fr/guide/anti-patterns/index.md"};function n(o,e,d,l,c,u){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="collection-d-anti-patterns-rxjs" tabindex="-1">Collection d&#39;Anti-patterns RxJS <a class="header-anchor" href="#collection-d-anti-patterns-rxjs" aria-label="Permalink to &quot;Collection d&#39;Anti-patterns RxJS&quot;">​</a></h1><p>RxJS est une bibliothèque puissante pour la programmation réactive, mais une utilisation incorrecte peut créer un terrain fertile pour les bugs et diminuer la maintenabilité. Cette section présente les erreurs courantes lors de l&#39;utilisation de RxJS avec TypeScript et les meilleures pratiques pour les éviter.</p><h2 id="objectif-de-cette-section" tabindex="-1">Objectif de cette section <a class="header-anchor" href="#objectif-de-cette-section" aria-label="Permalink to &quot;Objectif de cette section&quot;">​</a></h2><ul><li><strong>Prévenir les bugs</strong> : Comprendre les erreurs courantes à l&#39;avance pour éviter les problèmes lors de l&#39;implémentation</li><li><strong>Améliorer la maintenabilité</strong> : Maîtriser des patterns de code lisibles et testables</li><li><strong>Optimiser les performances</strong> : Apprendre des techniques pour prévenir les fuites mémoire et les traitements inutiles</li></ul><h2 id="liste-des-anti-patterns" tabindex="-1">Liste des anti-patterns <a class="header-anchor" href="#liste-des-anti-patterns" aria-label="Permalink to &quot;Liste des anti-patterns&quot;">​</a></h2><p>Cette section couvre 17 anti-patterns.</p><h3 id="🔴-problemes-critiques" tabindex="-1">🔴 Problèmes critiques <a class="header-anchor" href="#🔴-problemes-critiques" aria-label="Permalink to &quot;🔴 Problèmes critiques&quot;">​</a></h3><p>Ces patterns peuvent avoir un impact sérieux sur votre application.</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Problème</th><th>Impact</th></tr></thead><tbody><tr><td><strong><a href="./common-mistakes#1-subject-の外部公開">Exposition externe des Subjects</a></strong></td><td>Exposer directement un <code>Subject</code> permettant aux externes d&#39;appeler <code>next()</code></td><td>Imprévisibilité de la gestion d&#39;état, difficulté de débogage</td></tr><tr><td><strong><a href="./common-mistakes#2-ネストした-subscribe-コールバック地獄">Souscriptions imbriquées</a></strong></td><td>Appeler <code>subscribe</code> à l&#39;intérieur d&#39;un autre <code>subscribe</code></td><td>Callback hell, complexité de gestion d&#39;erreurs</td></tr><tr><td><strong><a href="./flag-management">Prolifération de drapeaux de gestion d&#39;état</a></strong></td><td>Gérer l&#39;état avec 17 drapeaux booléens, persistance de pensée impérative</td><td>Faible lisibilité, maintenance difficile, source de bugs</td></tr><tr><td><strong><a href="./subscribe-if-hell">Imbrication if dans subscribe</a></strong></td><td>Branchements conditionnels complexes dans <code>subscribe</code> (3+ imbrications)</td><td>Faible lisibilité, tests difficiles, contraire à la pensée déclarative</td></tr><tr><td><strong><a href="./common-mistakes#3-unsubscribe-忘れ-メモリリーク">Oubli d&#39;unsubscribe</a></strong></td><td>Ne pas se désabonner des flux infinis</td><td>Fuites mémoire, gaspillage de ressources</td></tr><tr><td><strong><a href="./common-mistakes#4-sharereplay-の誤用">Mauvaise utilisation de shareReplay</a></strong></td><td>Utiliser <code>shareReplay</code> sans comprendre son fonctionnement</td><td>Référence à des données périmées, fuites mémoire</td></tr></tbody></table><h3 id="🟡-problemes-necessitant-attention" tabindex="-1">🟡 Problèmes nécessitant attention <a class="header-anchor" href="#🟡-problemes-necessitant-attention" aria-label="Permalink to &quot;🟡 Problèmes nécessitant attention&quot;">​</a></h3><p>Ceux-ci peuvent poser problème dans certaines situations spécifiques.</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Problème</th><th>Impact</th></tr></thead><tbody><tr><td><strong><a href="./common-mistakes#5-map-での副作用">Effets de bord dans map</a></strong></td><td>Modifier l&#39;état dans l&#39;opérateur <code>map</code></td><td>Comportement imprévisible, tests difficiles</td></tr><tr><td><strong><a href="./common-mistakes#6-cold-hot-observable-の違いの無視">Ignorer Cold/Hot</a></strong></td><td>Ne pas considérer la nature de l&#39;Observable</td><td>Exécutions en double, comportement inattendu</td></tr><tr><td><strong><a href="./promise-observable-mixing">Mélange avec Promises</a></strong></td><td>Ne pas convertir correctement entre Promise et Observable</td><td>Non-annulable, gestion d&#39;erreurs insuffisante</td></tr><tr><td><strong><a href="./common-mistakes#8-バックプレッシャーの無視">Ignorer le backpressure</a></strong></td><td>Négliger le contrôle des événements à haute fréquence</td><td>Dégradation des performances, gel de l&#39;UI</td></tr></tbody></table><h3 id="🔵-problemes-de-qualite-de-code" tabindex="-1">🔵 Problèmes de qualité de code <a class="header-anchor" href="#🔵-problemes-de-qualite-de-code" aria-label="Permalink to &quot;🔵 Problèmes de qualité de code&quot;">​</a></h3><p>Ceux-ci ne sont pas des bugs directs mais réduisent la qualité du code.</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Problème</th><th>Impact</th></tr></thead><tbody><tr><td><strong><a href="./common-mistakes#9-エラーの握りつぶし">Suppression d&#39;erreurs</a></strong></td><td>Ne pas gérer correctement les erreurs</td><td>Débogage difficile, expérience utilisateur dégradée</td></tr><tr><td><strong><a href="./common-mistakes#10-dom-イベントサブスクリプションのリーク">Fuites d&#39;événements DOM</a></strong></td><td>Ne pas libérer les écouteurs d&#39;événements DOM</td><td>Fuites mémoire, dégradation des performances</td></tr><tr><td><strong><a href="./common-mistakes#11-型安全性の欠如-any-の多用">Manque de sécurité de type</a></strong></td><td>Utilisation excessive de <code>any</code></td><td>Erreurs au runtime, refactoring difficile</td></tr><tr><td><strong><a href="./common-mistakes#12-不適切なオペレーター選択">Sélection d&#39;opérateur inappropriée</a></strong></td><td>Utiliser un opérateur inadapté à l&#39;objectif</td><td>Inefficacité, comportement inattendu</td></tr><tr><td><strong><a href="./common-mistakes#13-過度な複雑化">Complexification excessive</a></strong></td><td>Complexifier des traitements qui pourraient être simples</td><td>Faible lisibilité, maintenance difficile</td></tr><tr><td><strong><a href="./one-liner-hell">Enfer du one-liner</a></strong></td><td>Mélange de définition de flux, transformation et souscription</td><td>Débogage difficile, tests difficiles, faible lisibilité</td></tr><tr><td><strong><a href="./common-mistakes#14-subscribe-内での状態変更">Modification d&#39;état dans subscribe</a></strong></td><td>Modifier directement l&#39;état dans <code>subscribe</code></td><td>Tests difficiles, source de bugs</td></tr><tr><td><strong><a href="./common-mistakes#15-テストの欠如">Absence de tests</a></strong></td><td>Ne pas écrire de tests pour le code RxJS</td><td>Régression, refactoring difficile</td></tr></tbody></table><h2 id="comment-progresser-dans-l-apprentissage" tabindex="-1">Comment progresser dans l&#39;apprentissage <a class="header-anchor" href="#comment-progresser-dans-l-apprentissage" aria-label="Permalink to &quot;Comment progresser dans l&#39;apprentissage&quot;">​</a></h2><ol><li>Étudier en détail les 15 anti-patterns dans <strong><a href="./common-mistakes">Erreurs courantes et solutions</a></strong></li><li>Chaque anti-pattern comprend des exemples de code &quot;mauvais&quot; et &quot;bons&quot;</li><li>Réviser votre code avec la <strong><a href="./checklist">Checklist d&#39;évitement des anti-patterns</a></strong></li><li>Mettre en pratique les meilleures pratiques et les partager au sein de l&#39;équipe</li></ol><h2 id="sections-connexes" tabindex="-1">Sections connexes <a class="header-anchor" href="#sections-connexes" aria-label="Permalink to &quot;Sections connexes&quot;">​</a></h2><p>Après avoir appris les anti-patterns, consultez également les sections suivantes.</p><ul><li><strong><a href="/RxJS-with-TypeScript/fr/guide/error-handling/strategies">Gestion des erreurs</a></strong> - Stratégies appropriées de gestion d&#39;erreurs</li><li><strong><a href="/RxJS-with-TypeScript/fr/guide/testing/unit-tests">Méthodes de test</a></strong> - Comment tester le code RxJS</li><li><strong><a href="/RxJS-with-TypeScript/fr/guide/operators/">Comprendre les opérateurs</a></strong> - Comment choisir les bons opérateurs</li></ul><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><ol><li>Commencez par <strong><a href="./common-mistakes">Erreurs courantes et solutions</a></strong> pour apprendre les anti-patterns pratiques et leurs solutions.</li><li>Après l&#39;apprentissage, révisez votre code actuel avec la <strong><a href="./checklist">Checklist d&#39;évitement des anti-patterns</a></strong>.</li></ol><hr><p><strong>Important</strong> : Ces anti-patterns sont fréquemment rencontrés dans les projets réels. Les comprendre tôt vous permettra d&#39;écrire du code RxJS de haute qualité.</p>',24)])])}const b=t(a,[["render",n]]);export{m as __pageData,b as default};
